func publishOpBadge(op string) string {
	switch op {
	case "created", "added":
		return "ok"
	case "deleted", "removed":
		return "warn"
	case "updated":
		return "info"
	default:
		return "neutral"
	}
}

func hasAnyChanges(items []PublishOutcome) bool {
	for _, it := range items {
		if len(it.Changes) > 0 {
			return true
		}
	}
	return false
}

func confirmLabel(items []PublishOutcome) string {
	if len(items) == 0 {
		return "Nothing to publish"
	}
	return fmt.Sprintf("Apply %d Drafts", len(items))
}

